<?php
namespace App\Models\Purchases; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
#[Fillable(['purchase_invoice_id','goods_receipt_item_id','product_id','name_snapshot','hsn_sac','quantity','unit_price','taxable_value','tax_rate','cgst_amount','sgst_amount','igst_amount','cess_amount','line_total'])]
class PurchaseInvoiceItem extends Model {protected function casts():array{return ['quantity'=>'decimal:3','unit_price'=>'decimal:2','taxable_value'=>'decimal:2','tax_rate'=>'decimal:3','cgst_amount'=>'decimal:2','sgst_amount'=>'decimal:2','igst_amount'=>'decimal:2','cess_amount'=>'decimal:2','line_total'=>'decimal:2'];}public function invoice():BelongsTo{return $this->belongsTo(PurchaseInvoice::class,'purchase_invoice_id');}}
